css:
.loader {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  border-radius: 999px;
  background: #6366f1;
  padding: 12px 18px;
  color: #fff;
}
.loader i {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: currentColor;
  animation: blink 0.95s ease-in-out infinite;
}
.loader i:nth-child(2) { animation-delay: 0.15s; }
.loader i:nth-child(3) { animation-delay: 0.3s; }
@keyframes blink {
  0%, 100% { opacity: 0.28; transform: scale(0.8); }
  50% { opacity: 1; transform: scale(1); }
}
